import{c as s,cG as a,cb as n,c8 as t,cf as e,cT as l,ce as i}from"./chunks/framework.BlkIsu1j.js";const p=JSON.parse('{"title":"03. RISC-V 体系结构概览","description":"","frontmatter":{"title":"03. RISC-V 体系结构概览","outline":"deep","layout":"doc","prev":{"text":"02. 数制与数据表示","link":"/lang/assembly/02_number_systems"},"next":{"text":"04. 第一个 RISC-V 程序","link":"/lang/assembly/04_first_program"},"sidebar":true,"date":"2026-05-31T10:00:00.000Z"},"headers":[],"relativePath":"lang/assembly/03_architecture.md","filePath":"lang/assembly/03_architecture.md","lastUpdated":1780200373000}'),d={id:"frontmatter-title",tabindex:"-1"};const r=s({name:"lang/assembly/03_architecture.md"},[["render",function(s,p,r,o,c,g){return a(),n("div",null,[t("h1",d,[e(l(s.$frontmatter.title)+" ",1),p[0]||(p[0]=t("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),p[1]||(p[1]=i('<p>汇编程序员需要的心智模型——寄存器、内存、指令执行周期——就是计算机体系结构的核心。本章建立 RISC-V 体系结构的全景图，为后续的指令学习打好框架。</p><h2 id="冯·诺依曼模型" tabindex="-1">冯·诺依曼模型 <a class="header-anchor" href="#冯·诺依曼模型" aria-label="Permalink to “冯·诺依曼模型”">​</a></h2><p>1945 年，John von Neumann 在一份备忘录中描述了现代计算机的基本架构。七十年后，几乎所有通用计算机仍在遵循这个模型。</p><p><strong>五大组件</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>+----------+     +----------+</span></span>\n<span class="line"><span>| 输入设备  |     | 输出设备  |</span></span>\n<span class="line"><span>+----+-----+     +-----+----+</span></span>\n<span class="line"><span>     |                  ^</span></span>\n<span class="line"><span>     v                  |</span></span>\n<span class="line"><span>+-------------------------------+</span></span>\n<span class="line"><span>|          内存（Memory）         |</span></span>\n<span class="line"><span>|    指令和数据共享同一存储空间     |</span></span>\n<span class="line"><span>+-------------------------------+</span></span>\n<span class="line"><span>     |                  ^</span></span>\n<span class="line"><span>     v                  |</span></span>\n<span class="line"><span>+----------+     +----------+</span></span>\n<span class="line"><span>| 控制器    |----&gt;| 运算器    |</span></span>\n<span class="line"><span>| (PC,译码) |     | (ALU)    |</span></span>\n<span class="line"><span>+----------+     +----------+</span></span>\n<span class="line"><span>    CPU</span></span></code></pre></div><p><strong>对汇编程序员的核心意义</strong>：</p><ul><li><strong>存储程序概念</strong>：程序指令和数据存储在<strong>同一个内存</strong>中。这意味着程序可以修改自身代码（尽管现代 OS 通常禁止），也意味着缓冲区溢出可能覆盖返回地址——这是一种安全漏洞</li><li><strong>PC（程序计数器）</strong>指向当前要执行的指令所在的内存地址。改变 PC = 改变执行路径，这是所有跳转和分支的本质</li><li><strong>内存可同时存放代码和数据</strong>：.text 段放指令、.data 段放全局变量、stack 段放局部变量和返回地址。从 CPU 视角，它们都只是一段地址区间</li></ul><h2 id="寄存器文件" tabindex="-1">寄存器文件 <a class="header-anchor" href="#寄存器文件" aria-label="Permalink to “寄存器文件”">​</a></h2><p>寄存器是 CPU 内部最快的数据存储——零周期延迟，直接连在 ALU 上。RISC 架构的核心设计决策之一就是<strong>提供足够多的通用寄存器以最小化内存访问</strong>。</p><p><strong>RV64I 寄存器文件</strong>：32 个 64 位通用寄存器，编号 x0-x31。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>x0  ┌────────────────────────────────┐  恒为零（硬连线）</span></span>\n<span class="line"><span>x1  ├────────────────────────────────┤  返回地址</span></span>\n<span class="line"><span>x2  ├────────────────────────────────┤  栈指针</span></span>\n<span class="line"><span>x3  ├────────────────────────────────┤  全局指针</span></span>\n<span class="line"><span>x4  ├────────────────────────────────┤  线程指针</span></span>\n<span class="line"><span>x5  ├────────────────────────────────┤</span></span>\n<span class="line"><span> ... │         临时/参数/保存          │</span></span>\n<span class="line"><span>x31 └────────────────────────────────┘</span></span></code></pre></div><table tabindex="0"><thead><tr><th>寄存器</th><th>描述</th></tr></thead><tbody><tr><td>x0</td><td><strong>硬连线恒为 0</strong>。写入 x0 的数据被丢弃，读 x0 永远返回 0。这是 RISC-V 设计中最精妙的一处——用 x0 替代了很多本来需要特殊指令的操作（例如 <code>sub x5, x0, x6</code> 实现取负（<code>neg</code>），<code>beq x0, x0, label</code> 实现无条件跳转）</td></tr><tr><td>x1-x31</td><td>通用寄存器，可读写。宽度在 RV64 中为 64 位</td></tr></tbody></table><p><strong>PC（程序计数器）</strong> 独立于这 32 个寄存器。PC 保存当前指令的地址（64 位），不是通用寄存器的一部分——你不能像访问 x5 那样直接读写 PC。修改 PC 的唯一方式是通过跳转和分支指令（JAL、JALR、BEQ、BNE 等），或者通过 AUIPC 间接读取 PC 相关信息。</p><p><strong>寄存器 vs 内存</strong>：寄存器在 CPU 内部，访问延迟 0 个周期（或 1 个周期在深层流水线中）。内存（DRAM）在 CPU 外部，访问延迟通常几十到几百纳秒。RISC 架构正是为了最大化利用寄存器、最小化内存访问而设计的。L1/L2/L3 Cache 缓存用于缓解这一差距，但对汇编程序员来说，寄存器分配的好坏直接影响性能。</p><h2 id="risc-v-寄存器-abi-名称" tabindex="-1">RISC-V 寄存器 ABI 名称 <a class="header-anchor" href="#risc-v-寄存器-abi-名称" aria-label="Permalink to “RISC-V 寄存器 ABI 名称”">​</a></h2><p>寄存器只有编号（x0-x31）是硬件事实；赋予它们语义的 ABI 名称是<strong>约定</strong>，不是硬件强制。但遵循 ABI 约定是代码能与编译器生成的函数互操作的先决条件。</p><table tabindex="0"><thead><tr><th>寄存器</th><th>ABI 名</th><th>用途</th><th>调用保存</th></tr></thead><tbody><tr><td>x0</td><td>zero</td><td>恒为零</td><td>N/A</td></tr><tr><td>x1</td><td>ra</td><td>返回地址（Return Address）</td><td>调用者</td></tr><tr><td>x2</td><td>sp</td><td>栈指针（Stack Pointer）</td><td>被调用者</td></tr><tr><td>x3</td><td>gp</td><td>全局指针（Global Pointer）</td><td>—</td></tr><tr><td>x4</td><td>tp</td><td>线程指针（Thread Pointer）</td><td>—</td></tr><tr><td>x5</td><td>t0</td><td>临时寄存器 0</td><td>调用者</td></tr><tr><td>x6-x7</td><td>t1-t2</td><td>临时寄存器</td><td>调用者</td></tr><tr><td>x8</td><td>s0 / fp</td><td>保存寄存器 0 / 帧指针</td><td>被调用者</td></tr><tr><td>x9</td><td>s1</td><td>保存寄存器 1</td><td>被调用者</td></tr><tr><td>x10-x11</td><td>a0-a1</td><td>函数参数 / 返回值</td><td>调用者</td></tr><tr><td>x12-x17</td><td>a2-a7</td><td>函数参数</td><td>调用者</td></tr><tr><td>x18-x27</td><td>s2-s11</td><td>保存寄存器</td><td>被调用者</td></tr><tr><td>x28-x31</td><td>t3-t6</td><td>临时寄存器</td><td>调用者</td></tr></tbody></table><p><strong>调用者保存 vs 被调用者保存</strong>：</p><ul><li><strong>调用者保存</strong>（caller-saved）：调用函数前，调用者负责把寄存器值保存到栈上。被调用函数可以随意覆盖这些寄存器</li><li><strong>被调用者保存</strong>（callee-saved）：被调用函数如果要使用这些寄存器，必须先把原始值保存到栈上，返回前恢复</li></ul><p>理解这一约定的实际意义：如果你在写汇编函数，临时变量用 t0-t6（无需保存），跨函数调用的变量用 s0-s11（需配合栈帧）。第 11 章将详细讲解 RISC-V 的完整调用约定。</p><h2 id="内存地址空间" tabindex="-1">内存地址空间 <a class="header-anchor" href="#内存地址空间" aria-label="Permalink to “内存地址空间”">​</a></h2><p><strong>地址空间</strong>：RV64 理论上有 $2^{64}$ 字节的虚拟地址空间（16 EB），但实际实现通常支持 48 位（256 TB）或 39 位（512 GB）——与 x86-64 和 ARM64 一致。原因很简单：全 64 位地址需要更深的页表，而没有任何应用需要 16 EB 的虚拟内存。</p><p><strong>内存按字节编址</strong>。地址 N 指向一个独立的字节。但指令有对齐要求：</p><ul><li>4 字节指令（RV64I 标准指令）必须对齐到 4 字节边界（地址 mod 4 == 0）</li><li>2 字节指令（C 扩展）对齐到 2 字节边界</li><li>数据 load/store 在硬件不支持时，非对齐访问会触发异常（某些实现支持硬件非对齐访问）</li></ul><p><strong>Load-Store 架构</strong>是 RISC 的基石。RISC-V 严格分离：</p><ul><li><strong>ALU 操作</strong>（add, sub, and, or, sll, ...）：操作数<strong>只能来自寄存器</strong>，结果<strong>只能写入寄存器</strong></li><li><strong>Load 操作</strong>（ld, lw, lh, lb, ...）：数据从<strong>内存流向寄存器</strong></li><li><strong>Store 操作</strong>（sd, sw, sh, sb）：数据从<strong>寄存器流向内存</strong></li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>正确:                        错误（不支持）:</span></span>\n<span class="line"><span>ld  x5, 0(x10)               add x5, 0(x10), x6   # RISC-V 不允许</span></span>\n<span class="line"><span>add x5, x5, x6               add x5, x5, (x10)    # 内存 ↔ 寄存器 混合操作</span></span></code></pre></div><p>对比 x86：<code>add eax, [rbx]</code> 一条指令同时完成内存读取和加法。RISC-V 需要两条（<code>ld</code> + <code>add</code>），单条指令更长，但每条指令的执行时间更可预测——这对流水线和超标量设计极为重要。</p><p><strong>地址空间布局</strong>（Linux RV64 典型）：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>0x0000_0000_0000_0000 ─┬─ 不可访问（NULL）</span></span>\n<span class="line"><span>                       │</span></span>\n<span class="line"><span>0x0001_0000_0000_0000 ─┼─ 用户代码 (.text)</span></span>\n<span class="line"><span>                       │  用户数据 (.data, .bss)</span></span>\n<span class="line"><span>                       │  堆 (heap, brk/sbrk 向上增长)</span></span>\n<span class="line"><span>                       │  ...</span></span>\n<span class="line"><span>                       │  栈 (stack, 向下增长)</span></span>\n<span class="line"><span>0x0000_7FFF_FFFF_FFFF ─┼─ 用户空间上限（48位实现）</span></span>\n<span class="line"><span>                       │</span></span>\n<span class="line"><span>0xFFFF_8000_0000_0000 ─┼─ 内核空间</span></span>\n<span class="line"><span>                       │</span></span>\n<span class="line"><span>0xFFFF_FFFF_FFFF_FFFF ─┴─ 内核空间顶</span></span></code></pre></div><p>这个布局和 x86-64/ARM64 基本一致——都是用户空间低 48 位，内核空间高 48 位。</p><h2 id="指令执行周期" tabindex="-1">指令执行周期 <a class="header-anchor" href="#指令执行周期" aria-label="Permalink to “指令执行周期”">​</a></h2><p>了解 CPU 如何&quot;吃掉&quot;一条指令，才能真正理解汇编程序的运行时行为。</p><p><strong>经典五级流水线</strong>（RISC 的教科书实现）：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>取指(Fetch)  →  译码(Decode)  →  执行(Execute)  →  访存(Memory)  →  写回(Writeback)</span></span>\n<span class="line"><span>     │                                                              │</span></span>\n<span class="line"><span>     └────────────────── PC 更新（顺序 PC+4 / 跳转改 PC）─────────────┘</span></span></code></pre></div><ol><li><strong>取指（Fetch）</strong>：从 PC 指向的地址读取 4 字节（C 扩展时 2 字节），送入指令寄存器</li><li><strong>译码（Decode）</strong>：解析 opcode（7 位）确定格式类型（R/I/S/B/U/J），提取 rd、rs1、rs2、funct3、funct7、立即数等字段；从寄存器文件读出 rs1 和 rs2 的值</li><li><strong>执行（Execute）</strong>：ALU 完成运算——算术类指令直接计算，load/store 类计算地址（基址 + 偏移），分支类计算条件和目标地址</li><li><strong>访存（Memory）</strong>：<strong>仅 Load/Store 指令在这一阶段工作</strong>。Load 从数据缓存读取数据，Store 将数据写入数据缓存。其他指令（算术、分支、AUIPC 等）在此阶段空转</li><li><strong>写回（Writeback）</strong>：结果写入目标寄存器 rd（load 指令写读回的数据，ALU 指令写计算结果，JAL/JALR 写返回地址即 PC+4）</li></ol><p><strong>PC 更新</strong>：每条指令执行后 PC 默认 +4（顺序执行）。跳转/分支指令在 Execute 阶段计算出新 PC 值，覆盖默认的 +4。</p><p><strong>流水线的直观理解</strong>：不是一条指令走完五步再开始下一条，而是每条指令只占一级，五级流水线可以同时容纳五条处在不同阶段的指令：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>周期 1: I1 取指</span></span>\n<span class="line"><span>周期 2: I1 译码 | I2 取指</span></span>\n<span class="line"><span>周期 3: I1 执行 | I2 译码 | I3 取指</span></span>\n<span class="line"><span>周期 4: I1 访存 | I2 执行 | I3 译码 | I4 取指</span></span>\n<span class="line"><span>周期 5: I1 写回 | I2 访存 | I3 执行 | I4 译码 | I5 取指</span></span></code></pre></div><p>对汇编程序员而言，流水线的关键影响在于<strong>数据冒险（data hazard）</strong>：如果指令 I2 依赖 I1 的计算结果，而 I1 的结果要等到 Writeback 阶段才写入寄存器，I2 在 Decode 阶段就可能读到旧值。现代处理器用转发（forwarding）和流水线停顿（stall）处理这种情况。汇编层面可以手动调度指令顺序来减少停顿（第 18 章会涉及 <code>-O3</code> 编译优化时会讨论这点）。</p><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to “本章要点”">​</a></h2><ul><li>冯·诺依曼模型：指令和数据共享内存，PC 指向当前指令，改变 PC = 改变执行流</li><li>RV64I 提供 32 个 64 位通用寄存器，x0 硬连线恒为 0（写丢弃），PC 独立于寄存器文件</li><li>ABI 名称是约定而非硬件强制：a0-a7 传参、t0-t6 临时不需要保存、s0-s11 需被调用者保存</li><li>Load-Store 架构：ALU 操作只处理寄存器，内存访问由 ld/sd 等专用指令完成——与 x86 可直接操作内存的 add 根本不同</li><li>五级流水线（取指/译码/执行/访存/写回）是理解指令延迟和流水线冒险的基础</li></ul>',42))])}]]);export{p as __pageData,r as default};
